m = re.search(start_pat, s)
if not m:
    print("Failed to find malformed block start", file=sys.stderr); sys.exit(1)
end_pat = r'\s*continue;\s*\n\s*\}\s*'
m2 = re.search(end_pat, s[m.end():])
if not m2:
    print("Failed to find malformed block end", file=sys.stderr); sys.exit(1)
prefix = s[:m.start()]
suffix = s[m.end()+m2.end():]
# New corrected block
fixed = """auto *ExitVal = dyn_cast<PHINode>(PN.getIncomingValue(IncomingValIdx));
