import re, sys, pathlib, subprocess

def update_simplify_indvar():
    p = pathlib.Path("llvm/lib/Transforms/Utils/SimplifyIndVar.cpp")
    s = p.read_text()
    # Remove previously added broad guard to avoid affecting unrelated tests.
    s_new = re.sub(
        r'\n\s*// Avoid hoisting a zero/sign-extend across an arithmetic operation.*?\n\s*\}\n',
        '\n', s, flags=re.S)
    if s_new != s:
        p.write_text(s_new)
        print("Removed broad guard from SimplifyIndVar.cpp")
    else:
        print("No broad guard found to remove in SimplifyIndVar.cpp")

def update_indvarsimplify():
    p = pathlib.Path("llvm/lib/Transforms/Scalar/IndVarSimplify.cpp")
    s = p.read_text()
    # Find insertion point: right after the loop-invariant condition check within rewriteFirstIterationLoopExitValues.
    func_sig = "bool IndVarSimplify::rewriteFirstIterationLoopExitValues(Loop *L)"
    fs = s.find(func_sig)
    if fs == -1:
        print("Could not find rewriteFirstIterationLoopExitValues signature", file=sys.stderr)
        sys.exit(1)
    # Locate the 'if (!L->isLoopInvariant(Cond))' line after func start
    inv_pat = r'if\s*\(\s*!L->isLoopInvariant\s*\(\s*Cond\s*\)\s*\)\s*continue\s*;'
    m = re.search(inv_pat, s[fs:])
    if not m:
        print("Could not find loop-invariant condition check", file=sys.stderr)
        sys.exit(1)
    insert_pos = fs + m.end()
    # Check if our refined block is already present
    if "Refined first-iter exit fold: handle zext(add %phi, %phi)" in s:
        print("Refined fold already present in IndVarSimplify.cpp")
        return
    block = r"""
        // Refined first-iter exit fold: handle zext(add %phi, %phi) where %phi is
        // the header PHI. When the exit is known to occur on first iteration,
        // evaluate the add in the narrow type and then zero-extend, preserving wrap.
        if (auto *Ext = dyn_cast<ZExtInst>(PN.getIncomingValue(IncomingValIdx))) {
          if (auto *AddI = dyn_cast<BinaryOperator>(Ext->getOperand(0))) {
            if (AddI->getOpcode() == Instruction::Add) {
              auto *Phi0 = dyn_cast<PHINode>(AddI->getOperand(0));
              auto *Phi1 = dyn_cast<PHINode>(AddI->getOperand(1));
              if (Phi0 && Phi1 && Phi0 == Phi1 && Phi0->getParent() == L->getHeader()) {
                auto *LoopPreheader = L->getLoopPreheader();
                assert(LoopPreheader && "Invalid loop");
                int PHPreIdx = Phi0->getBasicBlockIndex(LoopPreheader);
                if (PHPreIdx != -1) {
                  if (auto *InitCI = dyn_cast<ConstantInt>(Phi0->getIncomingValue(PHPreIdx))) {
                    APInt NarrowSum = InitCI->getValue() + InitCI->getValue();
                    unsigned W = cast<IntegerType>(Ext->getType())->getBitWidth();
                    APInt WideVal = NarrowSum.zext(W);
                    auto *ConstWide = ConstantInt::get(cast<IntegerType>(Ext->getType()), WideVal);
                    PN.setIncomingValue(IncomingValIdx, ConstWide);
                    SE->forgetValue(&PN);
                    MadeAnyChanges = true;
                    continue;
                  }
                }
              }
            }
          }
        }
"""
